// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:collection/collection.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/views/components/custom_dialog.dart';
import 'package:baseball_detector_flutter/views/hooks/use_debounce.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_subscription_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class RecordingFab extends HookConsumerWidget {
  const RecordingFab({
    required this.currentSession,
    required this.teamId,
    required this.canSubscribe,
    super.key,
  });

  final Session currentSession;
  final String teamId;
  final bool canSubscribe;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final showSubscriptionPage = useSubscriptionPage();
    final goToSubscription = useDebounce(showSubscriptionPage);
    final teamList = ref.watch(teamListControllerProvider);

    final fabState = useFabState(
      session: currentSession,
      teamId: teamId,
      canSubscribe: canSubscribe,
    );

    switch (fabState) {
      case FabState.available:
        return FloatingActionButton(
          backgroundColor:
              Theme.of(context).floatingActionButtonTheme.backgroundColor,
          onPressed: () async {
            try {
              final isSupported =
                  await KnowhereConfigurableCamera.getSingletonObject()
                      .isSupportedDevice();

              if (isSupported != true && context.mounted) {
                final shouldContinue = await showDialog<bool>(
                  context: context,
                  barrierDismissible: false,
                  builder: (context) => CustomDialog.oneMessage(
                    title: context.l10n
                        .session_details_page__device_unsupported_dialog_title,
                    messageText: context.l10n
                        .session_details_page__device_unsupported_dialog_message,
                    aboveButtonText: context.l10n
                        .session_details_page__device_unsupported_dialog_continue,
                    belowButtonText: context.l10n
                        .session_details_page__device_unsupported_dialog_cancel,
                    isAbovePositive: true,
                    isBelowPositive: false,
                    aboveButtonAction: (dialogContext) {
                      Navigator.of(dialogContext).pop(true);
                    },
                    belowButtonAction: (dialogContext) {
                      Navigator.of(dialogContext).pop(false);
                    },
                  ),
                );

                if (shouldContinue != true) {
                  return;
                }
              }
            } catch (e) {
              debugPrint('Failed to check device support: $e');
            }

            if (!context.mounted) return;

            Navigator.of(context, rootNavigator: true).pushNamed(
              AppRouter.recordingPage,
              arguments: {
                'sessionId': currentSession.id!,
                'sessionCreatedAt': currentSession.createdAt ?? DateTime.now(),
                'teamId': teamId,
              },
            );
          },
          child: const Icon(Icons.videocam_outlined),
        );

      case FabState.needsSubscription:
        return FloatingActionButton(
          backgroundColor: ColorManager.secondaryText,
          onPressed: () {
            if (canSubscribe) {
              final teams = teamList.valueOrNull;
              if (teams == null || teams.hasLeft) return;
              final team = teams.right.firstWhereOrNull((t) => t.id == teamId);
              goToSubscription.call(team);
            }
          },
          child: Icon(
            Icons.workspace_premium,
            color: Colors.yellow[700],
          ),
        );

      case FabState.unavailable:
        return FloatingActionButton(
          backgroundColor: context.isDarkMode
              ? ColorManager.darkSecondaryText
              : ColorManager.secondaryText,
          onPressed: null,
          child: const Icon(Icons.videocam_outlined),
        );
    }
  }
}

